mapper.select:
SELECT kc.id, kc.title, kc.summary, kc.content_type as contentType, kc.cover_image as coverImage, kc.category_id as categoryId, kc.category_name as categoryName, kc.view_count as viewCount, kc.collect_count as collectCount, kc.like_count as likeCount, kc.share_count as shareCount, kc.author_name as authorName, kc.is_top as isTop, kc.publish_time as publishTime, kc.status, kc.audit_status as auditStatus, CASE kc.content_type WHEN 'ARTICLE' THEN '文章' WHEN 'VIDEO' THEN '视频' WHEN 'CASE_STUDY' THEN '案例' WHEN 'FAQ' THEN '问答' ELSE '其他' END as contentTypeName, CASE kc.status WHEN 0 THEN '草稿' WHEN 1 THEN '已发布' WHEN 2 THEN '已下架' ELSE '未知' END as statusName, CASE kc.audit_status WHEN 0 THEN '待审核' WHEN 1 THEN '已通过' WHEN 2 THEN '未通过' ELSE '未知' END as auditStatusName, CASE WHEN kc.is_top = 1 THEN '是' ELSE '否' END as isTopName FROM knowledge_content kc WHERE kc.deleted = 0
AND kc.category_id = #{categoryId}
AND (kc.title LIKE CONCAT('%', #{keyword}, '%') OR kc.summary LIKE CONCAT('%', #{keyword}, '%'))
AND kc.content_type = #{contentType}
AND kc.status = #{status}
AND kc.audit_status = #{auditStatus}
ORDER BY kc.is_top DESC, kc.publish_time DESC
